import"./chunks/modulepreload-polyfill.js";const r=document.querySelector("#state"),n=document.querySelector("#capture"),s=document.querySelector("#pair");let e=!1;s.addEventListener("click",async()=>{const t=document.querySelector("#code").value.trim();if(!/^\d{6}$/.test(t)){r.textContent="Saisissez le code à 6 chiffres.";return}await chrome.storage.local.set({pairingCode:t}),r.textContent="Code enregistré — connexion locale en attente"});n.addEventListener("click",async()=>{const[t]=await chrome.tabs.query({active:!0,currentWindow:!0});if(!t.id){r.textContent="Onglet actif introuvable.";return}e=!e;const o=document.querySelector("#source").value,c=document.querySelector("#target").value;await chrome.storage.local.set({sourceLanguage:o,targetLanguage:c});const a=await chrome.runtime.sendMessage({type:e?"capture.start":"capture.stop",tabId:t.id});if(a&&!a.ok){e=!1,r.textContent=a.error??"La capture n’a pas démarré";return}n.textContent=e?"Arrêter la capture":"Capturer le son de cet onglet",n.classList.toggle("stop",e),r.textContent=e?"● Capture en cours":"Capture interrompue"});
